// Parse the JSON query sent by the AI Agent
const input = $('Execute Workflow Trigger').first().json;
const userId = input.userId;
const chatId = input.chatId;

// The AI Agent sends food data as JSON string in 'query' field
let parsed = {};
try {
  parsed = typeof input.query === 'string' ? JSON.parse(input.query) : input.query;
} catch(e) {
  // Fallback: try to extract from raw query string
  parsed = { food_name: input.query || 'Alimento', meal_type: 'snack', calories: 0, protein_g: 0, carbs_g: 0, fat_g: 0 };
}

return [{
  json: {
    userId,
    chatId,
    meal_type: parsed.meal_type || 'snack',
    description: parsed.food_name || parsed.description || 'Alimento',
    estimated_calories: parseInt(parsed.calories || parsed.estimated_calories || 0),
    estimated_protein_g: parseFloat(parsed.protein_g || parsed.estimated_protein_g || 0),
    estimated_carbs_g: parseFloat(parsed.carbs_g || parsed.estimated_carbs_g || 0),
    estimated_fat_g: parseFloat(parsed.fat_g || parsed.estimated_fat_g || 0)
  }
}];

parameters.query:
INSERT INTO daily_intake_logs (
  user_id, log_date, meal_type, description,
  estimated_calories, estimated_protein_g, estimated_carbs_g, estimated_fat_g
)
VALUES ($1, (NOW() AT TIME ZONE 'America/Bogota')::date, $2, $3, $4, $5, $6, $7)
RETURNING id, log_date, meal_type, description AS food_name, estimated_calories, estimated_protein_g;

parameters.jsCode:
const targets = $('Upsert Daily Targets').first().json;
const log = $('Insert Food Log').first().json;

return [{
  json: {
    success: true,
    registro: {
      meal_type: log.meal_type,
      calorias: log.estimated_calories,
      proteina_g: log.estimated_protein_g,
      descripcion: log.food_name,
      fecha: log.log_date
    },
    balance_dia: {
      calorias_consumidas: targets.calories_consumed,
      calorias_meta: targets.caloric_target,
      calorias_restantes: targets.caloric_target - targets.calories_consumed,
      proteina_consumida_g: targets.protein_consumed_g,
      proteina_meta_g: targets.protein_target_g,
      proteina_restante_g: targets.protein_target_g - targets.protein_consumed_g
    }
  }
}];

